import requests
import json

class WhatsAppSaaS:
    def __init__(self, base_url: str, api_key: str, instance_id: str):
        self.base_url = base_url.rstrip('/')
        self.api_key = api_key
        self.instance_id = instance_id
        self.headers = {
            'X-API-Key': api_key,
            'Content-Type': 'application/json'
        }

    def send_message(self, to: str, message: str) -> dict:
        """Send text message"""
        payload = {
            'instance_id': self.instance_id,
            'to': to,
            'type': 'TEXT',
            'content': message
        }
        response = requests.post(
            f'{self.base_url}/api/whatsapp/messages/send',
            headers=self.headers,
            json=payload
        )
        response.raise_for_status()
        return response.json()

    def send_media(self, to: str, media_type: str, media_url: str, caption: str = None) -> dict:
        """Send media message (IMAGE, VIDEO, DOCUMENT)"""
        payload = {
            'instance_id': self.instance_id,
            'to': to,
            'type': media_type.upper(),
            'media_url': media_url,
            'caption': caption
        }
        response = requests.post(
            f'{self.base_url}/api/whatsapp/messages/send',
            headers=self.headers,
            json=payload
        )
        response.raise_for_status()
        return response.json()

    def get_status(self) -> dict:
        """Get instance connection status"""
        response = requests.get(
            f'{self.base_url}/api/whatsapp/instances/{self.instance_id}/status',
            headers=self.headers
        )
        response.raise_for_status()
        return response.json()


# Usage
wa = WhatsAppSaaS(
    base_url='https://your-domain.com',
    api_key='wsa_your_api_key',
    instance_id='your-instance-uuid'
)

result = wa.send_message('6281234567890', 'Hello from Python!')
print(result)

