const axios = require('axios');

class WhatsAppSaaS {
  constructor(baseUrl, apiKey, instanceId) {
    this.baseUrl = baseUrl.replace(/\/+$/, '');
    this.apiKey = apiKey;
    this.instanceId = instanceId;
    this.client = axios.create({
      baseURL: this.baseUrl,
      headers: {
        'X-API-Key': apiKey,
        'Content-Type': 'application/json'
      }
    });
  }

  async sendMessage(to, message) {
    const response = await this.client.post('/api/whatsapp/messages/send', {
      instance_id: this.instanceId,
      to,
      type: 'TEXT',
      content: message
    });
    return response.data;
  }

  async sendMedia(to, type, mediaUrl, caption = null) {
    const response = await this.client.post('/api/whatsapp/messages/send', {
      instance_id: this.instanceId,
      to,
      type: type.toUpperCase(),
      media_url: mediaUrl,
      caption
    });
    return response.data;
  }

  async getStatus() {
    const response = await this.client.get(`/api/whatsapp/instances/${this.instanceId}/status`);
    return response.data;
  }

  async sendBulk(recipients, message) {
    const response = await this.client.post('/api/whatsapp/messages/send-bulk', {
      instance_id: this.instanceId,
      recipients,
      type: 'TEXT',
      content: message
    });
    return response.data;
  }
}

// Usage
const wa = new WhatsAppSaaS(
  'https://your-domain.com',
  'wsa_your_api_key',
  'your-instance-uuid'
);

(async () => {
  const result = await wa.sendMessage('6281234567890', 'Hello from Node.js!');
  console.log(result);
})();

module.exports = WhatsAppSaaS;

